import java.time.*;
import java.time.format.*;
import java.time.temporal.*;

public class Main {
    public static void main(String[] args) {
        // Current date and time
        LocalDate today = LocalDate.now();
        LocalTime now = LocalTime.now();
        LocalDateTime current = LocalDateTime.now();

        System.out.println("Today: " + today);
        System.out.println("Now: " + now);

        // Date manipulation
        LocalDate birthday = LocalDate.of(1990, Month.MARCH, 25);
        Period age = Period.between(birthday, today);
        System.out.println("Age: " + age.getYears() + " years, " + 
            age.getMonths() + " months");

        // Formatting
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("EEEE, MMMM d, yyyy");
        System.out.println("Formatted: " + today.format(fmt));

        // Parsing
        String dateStr = "2024-12-25";
        LocalDate parsed = LocalDate.parse(dateStr);
        System.out.println("Parsed: " + parsed.getDayOfWeek());

        // Duration
        Duration duration = Duration.ofHours(2).plusMinutes(30);
        System.out.println("Duration minutes: " + duration.toMinutes());
    }
}
